INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('907a7795-367a-4aac-b8f7-9eb0ea984a20', 'ad84d2a7-76cd-487f-b9a5-96bd34134b02', '1', 'Part 1: 介绍', '{\"title\": \"本次演讲概览\", \"points\": [\"目标与要点：了解原理、材料、应用与挑战\", \"演讲结构：技术原理、材料、应用、挑战、未来趋势\"]}', '{\"text\": \"页面标题：本次演讲概览\\n\\n页面文字：\\n- 目标与要点：了解原理、材料、应用与挑战\\n- 演讲结构：技术原理、材料、应用、挑战、未来趋势\", \"generated_at\": \"2026-01-19T02:16:59.124623\"}', 'ad84d2a7-76cd-487f-b9a5-96bd34134b02/pages/907a7795-367a-4aac-b8f7-9eb0ea984a20_v1.png', 'COMPLETED', '2026-01-19 02:16:48.355952', '2026-01-19 02:18:50.493540', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('375197f6-7360-465a-bbaf-3e45efa7d2ae', 'ad84d2a7-76cd-487f-b9a5-96bd34134b02', '2', 'Part 2: 背景与原理', '{\"title\": \"3D打印的定义与发展\", \"points\": [\"定义：逐层增材制造\", \"简史：从快速成型到广泛应用\"]}', '{\"text\": \"页面标题：3D打印的定义与发展\\n\\n页面文字：\\n- 定义：逐层堆叠增加物料形成实体零件\\n- 简史：从快速成型起步到如今广泛应用\", \"generated_at\": \"2026-01-19T02:17:01.079679\"}', 'ad84d2a7-76cd-487f-b9a5-96bd34134b02/pages/375197f6-7360-465a-bbaf-3e45efa7d2ae_v1.png', 'COMPLETED', '2026-01-19 02:16:48.355967', '2026-01-19 02:19:15.536824', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('2112cc7c-6fab-45db-9d65-9217cea04f78', 'ad84d2a7-76cd-487f-b9a5-96bd34134b02', '3', 'Part 2: 背景与原理', '{\"title\": \"工作流程与原理\", \"points\": [\"设计/建模\", \"切片\", \"打印执行\", \"后处理\"]}', '{\"text\": \"页面标题：工作流程与原理\\n\\n页面文字：\\n- 设计/建模：用CAD工具创建可打印的三维模型\\n- 切片：将模型切分为逐层的打印路径与参数\\n- 打印执行：设备依据路径逐层沉积或固化成形\\n- 后处理：去除支撑、打磨、清洁与表面优化\", \"generated_at\": \"2026-01-19T02:17:03.346686\"}', 'ad84d2a7-76cd-487f-b9a5-96bd34134b02/pages/2112cc7c-6fab-45db-9d65-9217cea04f78_v1.png', 'COMPLETED', '2026-01-19 02:16:48.355981', '2026-01-19 02:19:16.288349', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('33e742f1-9b52-4c73-b971-240c38aeb054', 'ad84d2a7-76cd-487f-b9a5-96bd34134b02', '4', 'Part 3: 打印技术与材料', '{\"title\": \"核心打印技术\", \"points\": [\"FDM（熔融沉积成型）\", \"SLA/DLP（光固化）\", \"金属3D打印（SLM/DMP）\", \"多材料与混合工艺\"]}', '{\"text\": \"页面标题：核心打印技术\\n\\n页面文字：\\n- 热塑材料挤出逐层成型，成本低且易上手\\n- 光敏树脂固化成型，精度高，表面光滑\\n- 金属粉末逐层堆积烧结，强度高，成本高\\n- 多材料打印与混合工艺，拓展性能与功能\", \"generated_at\": \"2026-01-19T02:17:06.862754\"}', 'ad84d2a7-76cd-487f-b9a5-96bd34134b02/pages/33e742f1-9b52-4c73-b971-240c38aeb054_v1.png', 'COMPLETED', '2026-01-19 02:16:48.355994', '2026-01-19 02:19:16.508373', NULL, NULL);
