INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('24eb2cef-feff-4202-8fa9-d43dbc3c98ca', '94c76730-2d75-4adf-b668-5ac2c11840b7', '9', '第四部分：建模核心流程实战', '{\"title\": \"第二步：基础形体创建与编辑\", \"points\": [\"添加基本体（Shift+A）：立方体、球体、圆柱、环面\", \"编辑模式（Tab）下选择顶点/边/面进行挤出（E）、循环切（Ctrl+R）、倒角（Ctrl+B）\", \"实例：用立方体挤出+倒角制作简约手机模型\"]}', NULL, NULL, 'DRAFT', '2026-02-02 03:11:38.272448', '2026-02-02 03:11:38.272457', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('0374b118-3238-4026-b3db-df245b7f3ac9', '94c76730-2d75-4adf-b668-5ac2c11840b7', '10', '第四部分：建模核心流程实战', '{\"title\": \"第三步：细分与平滑处理\", \"points\": [\"添加细分曲面修改器（Subdivision Surface）提升表面精度\", \"理解‘支持边’（Crease）与‘锐边标记’控制硬边效果\", \"避免过度细分导致性能下降——合理设置视图/渲染层级\"]}', NULL, NULL, 'DRAFT', '2026-02-02 03:11:38.273236', '2026-02-02 03:11:38.273241', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('2ead654e-3604-4913-9972-b567572f7d22', '94c76730-2d75-4adf-b668-5ac2c11840b7', '11', '第四部分：建模核心流程实战', '{\"title\": \"第四步：布尔运算与组合建模\", \"points\": [\"使用布尔修改器实现‘并集/差集/交集’（如在盒子上挖孔）\", \"注意事项：确保物体为闭合网格、应用缩放（Ctrl+A → Scale）、修复重叠面\", \"替代方案：手动切割+填充（Loop Cut + F）提高拓扑可控性\"]}', NULL, NULL, 'DRAFT', '2026-02-02 03:11:38.273495', '2026-02-02 03:11:38.273497', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('354bd8c0-06a4-460b-b1d5-656d9db8fafd', '94c76730-2d75-4adf-b668-5ac2c11840b7', '12', '第四部分：建模核心流程实战', '{\"title\": \"第五步：拓扑优化基础\", \"points\": [\"识别不良拓扑：三角面、N-gon、扭曲面、非流形几何\", \"重拓扑原则：四边面为主、布线沿形变方向、关键区域布线密集\", \"简易重拓扑：使用Shrinkwrap修改器辅助投射新网格\"]}', NULL, NULL, 'DRAFT', '2026-02-02 03:11:38.273753', '2026-02-02 03:11:38.273756', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('58dcd61e-2b9d-41e1-b6dd-6bb20e68d805', '94c76730-2d75-4adf-b668-5ac2c11840b7', '13', '第五部分：材质、光照与简单渲染', '{\"title\": \"基础材质设置（Blender EEVEE）\", \"points\": [\"新建材质→连接基础色（Base Color）与粗糙度（Roughness）节点\", \"使用图像纹理贴图（如木纹、金属划痕）增强真实感\", \"PBR流程简介：Albedo/Metallic/Roughness贴图作用\"]}', NULL, NULL, 'DRAFT', '2026-02-02 03:11:38.274028', '2026-02-02 03:11:38.274032', NULL, NULL);
