INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('397da4b7-f1f5-4cc7-82e8-03b94179471e', '7aea08e9-f4b7-4ae5-b7be-7c04115637bc', '3', NULL, '{\"title\": \"什么是3D建模？\", \"points\": [\"定义：在三维空间中创建物体数字几何体的过程\", \"本质：用点（Vertex）、线（Edge）、面（Face）构建虚拟对象\", \"输出目标：可用于渲染、动画、打印、交互、仿真等\", \"区别于2D绘图：具备X/Y/Z坐标、法线、体积、空间关系\"]}', NULL, NULL, 'FAILED', '2026-02-02 03:45:33.246721', '2026-02-02 05:19:33.625082', 'title_bullets', '{\"title\": \"什么是3D建模？\", \"bullets\": [{\"icon\": \"fa-book\", \"text\": \"定义：三维空间中创建数字几何体\", \"description\": \"通过计算机软件在X/Y/Z轴上构建物体的虚拟结构，是数字内容创作的基础环节\"}, {\"icon\": \"fa-cube\", \"text\": \"本质：点、线、面构成虚拟对象\", \"description\": \"以顶点（Vertex）为锚点，边（Edge）连接形成轮廓，面（Face）围合生成体积与表面\"}, {\"icon\": \"fa-project-diagram\", \"text\": \"输出目标高度通用化\", \"description\": \"生成模型可直接用于渲染出图、绑定动画、3D打印、实时交互或工程仿真等多元场景\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('d5e5e359-e1f4-455e-8ad0-52328db94ca5', '7aea08e9-f4b7-4ae5-b7be-7c04115637bc', '4', NULL, '{\"title\": \"3D建模的核心分类\", \"points\": [\"多边形建模（Polygon Modeling）——最常用，适合游戏/影视/工业\", \"曲面建模（NURBS/Spline）——高精度曲面，常用于汽车/工业设计\", \"参数化建模（Parametric Modeling）——基于规则与历史树，如Fusion 360\", \"体素建模（Voxel Modeling）——如MagicaVoxel，适合像素风与快速原型\"]}', NULL, NULL, 'FAILED', '2026-02-02 03:45:33.247105', '2026-02-02 05:19:33.627148', 'title_bullets', '{\"title\": \"3D建模的核心分类\", \"bullets\": [{\"icon\": \"fa-cube\", \"text\": \"多边形建模（Polygon Modeling）\", \"description\": \"最主流方法，基于顶点/边/面编辑，高效灵活，广泛应用于游戏、影视与工业设计。\"}, {\"icon\": \"fa-spline\", \"text\": \"曲面建模（NURBS/Spline）\", \"description\": \"以数学曲面为核心，精度高、连续性好，适用于汽车外形、精密模具等工业级设计。\"}, {\"icon\": \"fa-sliders-h\", \"text\": \"参数化建模（Parametric Modeling）\", \"description\": \"依赖历史树与可编辑参数，修改便捷、设计意图明确，典型代表为Fusion 360、SolidWorks。\"}]}');
