INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('2ffba01c-ab88-4e36-9020-542a47d29e29', '7aea08e9-f4b7-4ae5-b7be-7c04115637bc', '6', NULL, '{\"title\": \"多边形建模四大核心操作\", \"points\": [\"挤出（Extrude）：沿法线方向延伸面，构建体积\", \"倒角（Bevel）：柔化硬边，提升视觉真实感\", \"循环切（Loop Cut）：精准控制拓扑流，支撑变形\", \"桥接（Bridge）：连接两组边缘，生成过渡几何体\"]}', NULL, NULL, 'FAILED', '2026-02-02 03:45:33.247914', '2026-02-02 05:19:33.631235', 'title_bullets', '{\"title\": \"多边形建模四大核心操作\", \"bullets\": [{\"icon\": \"fa-arrow-up\", \"text\": \"挤出（Extrude）\", \"description\": \"沿面法线方向延伸生成新几何体，是构建体积与形态的基础操作\"}, {\"icon\": \"fa-cut\", \"text\": \"倒角（Bevel）\", \"description\": \"对边或顶点添加斜面过渡，柔化硬边、增强光照响应与真实感\"}, {\"icon\": \"fa-ruler-combined\", \"text\": \"循环切（Loop Cut）\", \"description\": \"沿拓扑流插入连续边环，精准控制布线密度，保障变形稳定性\"}, {\"icon\": \"fa-expand-arrows-alt\", \"text\": \"缩放/移动/旋转（Transform）\", \"description\": \"基础变换组合操作，实现顶点/边/面级微调，支撑精细化建模\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c0ddd32b-5f12-4f6b-bc07-dd95677ae79a', '7aea08e9-f4b7-4ae5-b7be-7c04115637bc', '7', NULL, '{\"title\": \"建模策略对比\", \"points\": []}', NULL, NULL, 'FAILED', '2026-02-02 03:45:33.248238', '2026-02-02 05:19:33.634958', 'two_column', '{\"title\": \"建模策略对比\", \"left\": {\"type\": \"bullets\", \"header\": \"自下而上建模（Bottom-up）\", \"content\": [\"fa-check 基于基础几何体逐步构建细节\", \"fa-lightbulb 适合硬表面/机械类模型\", \"fa-star 拓扑可控、修改灵活度高\", \"fa-check 初学者友好，逻辑清晰易掌握\"]}, \"right\": {\"type\": \"bullets\", \"header\": \"自上而下建模（Top-down）\", \"content\": [\"fa-check 先确立整体形态再细化局部\", \"fa-lightbulb 常用于有机角色/雕塑式建模\", \"fa-star 高效捕捉大形与动态比例\", \"fa-check 多结合雕刻工具（如ZBrush）\"]}}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('74f6f9f5-5f2c-4973-a7fc-eb230f9452c9', '7aea08e9-f4b7-4ae5-b7be-7c04115637bc', '8', NULL, '{\"title\": \"第三部分：工具与流程\", \"points\": []}', NULL, NULL, 'FAILED', '2026-02-02 03:45:33.248589', '2026-02-02 05:19:33.637189', 'section_title', '{\"section_number\": \"03\", \"title\": \"第三部分：工具与流程\", \"subtitle\": \"高效建模的支撑体系\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('8fca63ed-7d38-4bb2-ab38-d83199f6a089', '7aea08e9-f4b7-4ae5-b7be-7c04115637bc', '9', NULL, '{\"title\": \"主流3D软件概览\", \"points\": [\"Blender（免费开源）：全能型，建模/雕刻/动画/渲染一体化\", \"Maya（影视工业标准）：绑定与动画强大，建模模块稳健\", \"3ds Max（建筑/游戏常用）：建模与插件生态成熟\", \"ZBrush（雕刻王者）：百万级面数雕刻，细节表现极致\", \"Fusion 360 / SolidWorks（工程向）：参数化精确建模，用于制造与仿真\"]}', NULL, NULL, 'FAILED', '2026-02-02 03:45:33.248874', '2026-02-02 05:19:33.639515', 'title_bullets', '{\"title\": \"主流3D软件概览\", \"bullets\": [{\"icon\": \"fa-cube\", \"text\": \"Blender（免费开源）\", \"description\": \"全能型一体化方案，覆盖建模、雕刻、绑定、动画、渲染全流程，社区活跃，学习资源丰富。\"}, {\"icon\": \"fa-film\", \"text\": \"Maya（影视工业标准）\", \"description\": \"绑定与角色动画领域标杆，建模模块稳健可靠，广泛应用于好莱坞级影视项目制作。\"}, {\"icon\": \"fa-building\", \"text\": \"3ds Max（建筑/游戏常用）\", \"description\": \"建筑可视化与游戏资产开发主力工具，建模效率高，插件生态成熟，兼容性强。\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('05e22c80-ec05-4849-a6fd-9f1ac3a45ecf', '7aea08e9-f4b7-4ae5-b7be-7c04115637bc', '10', NULL, '{\"title\": \"标准建模工作流程\", \"points\": []}', '{\"text\": \"页面标题：标准建模工作流程\\n\\n\\n页面文字：\\n- 参考设定：导入三视图或概念图，设置比例基准  \\n- 基础搭建：用低面数几何体概括整体形体与比例  \\n- 细节推进：分阶段添加结构线、局部特征与拓扑优化  \\n- 检查修正：验证法线、布线、UV、面数与单位一致性  \\n- 输出准备：清理层级、重命名、导出适配目标平台格式\", \"generated_at\": \"2026-02-02T05:08:08.887669\"}', NULL, 'FAILED', '2026-02-02 03:45:33.249115', '2026-02-02 05:19:34.187179', 'process_steps', '{\"title\": \"标准建模工作流程\", \"steps\": [{\"number\": 1, \"label\": \"需求分析与参考收集\", \"description\": \"明确用途、风格、比例，搜集高清参考图与尺寸数据\", \"icon\": \"fa-search\"}, {\"number\": 2, \"label\": \"基础拓扑搭建\", \"description\": \"从低面数原型入手，构建主体结构与关键布线逻辑\", \"icon\": \"fa-cube\"}, {\"number\": 3, \"label\": \"细节雕刻与造型细化\", \"description\": \"在细分层级添加形态特征，保持拓扑合理性与可控性\", \"icon\": \"fa-sculpture\"}, {\"number\": 4, \"label\": \"拓扑重拓与优化\", \"description\": \"重构四边面主导的干净拓扑，适配动画/细分/渲染需求\", \"icon\": \"fa-sync-alt\"}, {\"number\": 5, \"label\": \"UV展开与布局\", \"description\": \"合理分岛、最小拉伸、预留间距，确保贴图精度与效率\", \"icon\": \"fa-project-diagram\"}, {\"number\": 6, \"label\": \"验证与交付准备\", \"description\": \"检查法线、非流形、比例单位、命名规范及引擎兼容性\", \"icon\": \"fa-check-circle\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('f6d0e1aa-9a1d-4fd9-a4fa-9511c4060d4d', '7aea08e9-f4b7-4ae5-b7be-7c04115637bc', '11', NULL, '{\"title\": \"第四部分：关键进阶要点\", \"points\": []}', NULL, NULL, 'FAILED', '2026-02-02 03:45:33.249348', '2026-02-02 05:19:33.603562', 'section_title', '{\"section_number\": \"04\", \"title\": \"第四部分：关键进阶要点\", \"subtitle\": \"夯实高阶建模能力的核心维度\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('761a70b4-3301-49c1-93d5-b594a667458b', '7aea08e9-f4b7-4ae5-b7be-7c04115637bc', '12', NULL, '{\"title\": \"拓扑质量三大黄金法则\", \"points\": [\"1. 尽量使用四边面（Quads）——保障变形稳定与细分平滑\", \"2. 避免三角面集中区与N-gon（>4边面）——防止渲染异常与动画撕裂\", \"3. 边流（Edge Flow）匹配形变逻辑——如面部围绕五官环形布线\"]}', NULL, NULL, 'FAILED', '2026-02-02 03:45:33.249901', '2026-02-02 05:19:33.616029', 'title_bullets', '{\"title\": \"拓扑质量三大黄金法则\", \"bullets\": [{\"icon\": \"fa-square\", \"text\": \"优先使用四边面（Quads）\", \"description\": \"保障蒙皮变形稳定性，支持Catmull-Clark细分平滑，避免扭曲与塌陷\"}, {\"icon\": \"fa-triangle\", \"text\": \"杜绝三角面集中区与N-gon\", \"description\": \"防止渲染着色异常、法线翻转及动画关键帧撕裂，确保绑定可靠性\"}, {\"icon\": \"fa-sync-alt\", \"text\": \"边流匹配形变逻辑\", \"description\": \"如面部采用环状+放射状布线，精准引导肌肉收缩与表情拉伸方向\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('b7d19990-485b-4e2f-9ca8-fd5da5bc2eeb', '7aea08e9-f4b7-4ae5-b7be-7c04115637bc', '13', NULL, '{\"title\": \"UV展开核心原则\", \"points\": [\"保持UV岛形状接近原始几何投影，减少拉伸\", \"合理分块：按材质/功能区域划分UV岛\", \"预留足够间距防贴图溢出\", \"利用自动展UV+手动调整结合（如Blender的Smart UV Project + Follow Active Quads）\"]}', NULL, NULL, 'FAILED', '2026-02-02 03:45:33.250271', '2026-02-02 05:19:33.585165', 'title_content', '{\"title\": \"UV展开核心原则\", \"content\": [\"✅ 保持UV岛形状贴近原始几何投影，最大限度降低纹理拉伸失真\", \"✅ 合理分块：按材质边界、功能区域或接缝逻辑划分UV岛，提升贴图绘制效率\", \"✅ 预留≥4像素间距（以1024贴图为基准），防止Mipmap采样或过滤导致贴图溢出串色\", \"✅ 优先沿自然接缝（如模型硬边、结构转折处）切割，兼顾拓扑合理性与展开整洁度\", \"✅ 避免UV岛重叠（除非明确需要复用贴图），确保每片几何拥有唯一UV坐标\"]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('df9d5221-4361-4fad-a300-a5f0af33e530', '7aea08e9-f4b7-4ae5-b7be-7c04115637bc', '14', NULL, '{\"title\": \"第五部分：应用与拓展\", \"points\": []}', NULL, NULL, 'FAILED', '2026-02-02 03:45:33.250655', '2026-02-02 05:19:33.622846', 'section_title', '{\"section_number\": \"05\", \"title\": \"第五部分：应用与拓展\", \"subtitle\": \"从建模到落地的全链路价值延伸\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('6f8d1b21-7bcb-4150-9a70-b89355ffbae3', '7aea08e9-f4b7-4ae5-b7be-7c04115637bc', '15', NULL, '{\"title\": \"3D建模的典型应用场景\", \"points\": [\"游戏开发：资产建模、LOD分级、引擎导入优化\", \"影视动画：角色/场景/道具建模，配合绑定与动力学\", \"工业设计：产品外观验证、结构装配模拟、3D打印准备\", \"建筑可视化：BIM协同、室内漫游、光照分析\", \"教育与医疗：解剖模型、分子结构、手术模拟\"]}', NULL, NULL, 'FAILED', '2026-02-02 03:45:33.250956', '2026-02-02 05:19:33.632922', 'title_bullets', '{\"title\": \"3D建模的典型应用场景\", \"bullets\": [{\"icon\": \"fa-gamepad\", \"text\": \"游戏开发\", \"description\": \"资产建模、LOD分级优化、引擎兼容性导入与性能调优\"}, {\"icon\": \"fa-film\", \"text\": \"影视动画\", \"description\": \"高精度角色/场景/道具建模，无缝对接绑定、蒙皮与动力学解算\"}, {\"icon\": \"fa-industry\", \"text\": \"工业设计\", \"description\": \"产品外观评审、结构装配干涉分析、面向3D打印的壁厚与支撑优化\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('00a3df1c-ab7a-4ef7-a501-1e7d97554d3d', '7aea08e9-f4b7-4ae5-b7be-7c04115637bc', '16', NULL, '{\"title\": \"常见问题与避坑指南\", \"points\": [\"❌ 忽视比例与单位设置 → 导致导入引擎后缩放错乱\", \"❌ 过早添加复杂细节 → 拓扑失控难以修改\", \"❌ UV重叠未检查 → 贴图显示错位\", \"❌ 法线朝向不统一 → 渲染出现黑面\", \"✅ 建议：勤保存版本、善用层级与命名、定期检查网格统计（面数/顶点/法线）\"]}', NULL, NULL, 'FAILED', '2026-02-02 03:45:33.251274', '2026-02-02 05:19:33.607724', 'title_bullets', '{\"title\": \"常见问题与避坑指南\", \"bullets\": [{\"icon\": \"fa-times-circle\", \"text\": \"忽视比例与单位设置\", \"description\": \"建模前未统一软件与引擎单位，导致导入后模型缩放异常、碰撞体错位\"}, {\"icon\": \"fa-times-circle\", \"text\": \"过早添加复杂细节\", \"description\": \"在基础拓扑未稳定前雕刻高模或布线细节，造成面数爆炸、修改成本剧增\"}, {\"icon\": \"fa-times-circle\", \"text\": \"UV重叠未检查\", \"description\": \"UV岛相互覆盖导致贴图采样冲突，出现纹理错位、颜色混杂、烘焙失败\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('3b921e08-6937-4c80-813c-157cadc0e12b', '7aea08e9-f4b7-4ae5-b7be-7c04115637bc', '17', NULL, '{\"title\": \"学习路径建议\", \"points\": [\"阶段1（1–2周）：熟悉Blender/Maya界面与基础操作\", \"阶段2（3–4周）：完成5个小型静物建模（杯子、椅子、手枪等）\", \"阶段3（2个月）：挑战中等复杂度项目（机器人头盔、卡通角色）\", \"阶段4（持续）：参与开源项目、临摹优秀作品、建立个人作品集\"]}', NULL, NULL, 'FAILED', '2026-02-02 03:45:33.251684', '2026-02-02 05:19:33.619160', 'title_bullets', '{\"title\": \"学习路径建议\", \"bullets\": [{\"icon\": \"fa-hourglass-start\", \"text\": \"阶段1（1–2周）：熟悉界面与基础操作\", \"description\": \"掌握Blender/Maya视图导航、选择/移动/旋转/缩放、基础修改器及快捷键体系\"}, {\"icon\": \"fa-cube\", \"text\": \"阶段2（3–4周）：完成5个小型静物建模\", \"description\": \"从杯子、椅子到手枪，聚焦比例把控、基础拓扑与干净布线，每件作品控制在2小时内完成\"}, {\"icon\": \"fa-robot\", \"text\": \"阶段3（2个月）：挑战中等复杂度项目\", \"description\": \"实践机器人头盔（硬表面）与卡通角色（有机建模），融入UV展开、简单材质与基础灯光验证\"}]}');
