INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('86043663-7dc7-4bc9-b5ae-4d41506169da', '6d0119d3-3549-44b6-a953-388d881cc817', '1', '第一部分：课程导览', '{\"title\": \"课程大纲\", \"points\": [\"C语言简介与历史\", \"开发环境搭建\", \"第一个C程序\", \"数据类型与变量\", \"运算符与表达式\", \"输入输出函数\", \"流程控制语句\", \"数组与字符串\", \"函数定义与调用\", \"指针基础\", \"结构体入门\", \"文件操作简介\", \"常见错误与调试技巧\", \"综合实训项目\", \"总结与进阶建议\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 05:50:02.504164', '2026-02-02 05:52:33.859877', 'toc', '{\"title\": \"课程大纲\", \"items\": [{\"index\": 1, \"text\": \"C语言简介与历史\"}, {\"index\": 2, \"text\": \"开发环境搭建\"}, {\"index\": 3, \"text\": \"第一个C程序\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('6d659002-ee24-4eab-8bbd-8d26d2809956', '6d0119d3-3549-44b6-a953-388d881cc817', '2', '第二部分：基础入门', '{\"title\": \"什么是C语言？\", \"points\": [\"1972年由丹尼斯·里奇在贝尔实验室开发\", \"面向过程、高效、可移植的系统级编程语言\", \"操作系统（如Linux）、嵌入式、驱动开发的核心语言\", \"学习C语言是理解计算机底层原理的重要途径\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 05:50:02.506822', '2026-02-02 05:52:45.848775', 'title_bullets', '{\"title\": \"什么是C语言？\", \"bullets\": [{\"icon\": \"fa-calendar\", \"text\": \"诞生于1972年\", \"description\": \"由丹尼斯·里奇在贝尔实验室主导开发，为UNIX操作系统重写而生\"}, {\"icon\": \"fa-cogs\", \"text\": \"面向过程的系统级语言\", \"description\": \"以函数为基本单元，强调算法逻辑与内存直接操控能力\"}, {\"icon\": \"fa-bolt\", \"text\": \"高效且贴近硬件\", \"description\": \"编译后生成紧凑机器码，执行效率高，资源占用极低\"}, {\"icon\": \"fa-globe\", \"text\": \"高度可移植\", \"description\": \"遵循ANSI/ISO标准，源代码经适配可在不同平台编译运行\"}, {\"icon\": \"fa-server\", \"text\": \"操作系统开发基石\", \"description\": \"Linux内核、UNIX变体及大量嵌入式系统核心均用C语言实现\"}, {\"icon\": \"fa-microchip\", \"text\": \"驱动与嵌入式首选\", \"description\": \"广泛应用于设备驱动、单片机、IoT终端等对性能和控制力要求严苛的领域\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('9c38e32f-950f-4618-b796-b6fdb7bfb9de', '6d0119d3-3549-44b6-a953-388d881cc817', '3', '第二部分：基础入门', '{\"title\": \"开发环境准备\", \"points\": [\"推荐工具：Visual Studio Code + GCC / Dev-C++ / Code::Blocks\", \"Windows下安装MinGW-w64\", \"macOS使用Xcode命令行工具或Homebrew安装gcc\", \"Linux直接使用内置gcc\", \"验证安装：终端输入 gcc --version\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 05:50:02.507148', '2026-02-02 05:52:48.771399', 'title_bullets', '{\"title\": \"开发环境准备\", \"bullets\": [{\"icon\": \"fa-tools\", \"text\": \"推荐集成工具链\", \"description\": \"Visual Studio Code 搭配 GCC 编译器，或 Dev-C++ / Code::Blocks 一体化IDE，兼顾轻量与功能完备性。\"}, {\"icon\": \"fa-windows\", \"text\": \"Windows 安装 MinGW-w64\", \"description\": \"下载并安装 MinGW-w64（推荐使用 MSYS2 或 WinLibs），配置 PATH 环境变量，验证 gcc --version 成功运行。\"}, {\"icon\": \"fa-apple\", \"text\": \"macOS 配置编译环境\", \"description\": \"首选 Xcode 命令行工具（xcode-select --install）；或通过 Homebrew 执行 brew install gcc，使用 gcc-14 等别名调用。\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a480ae54-f123-4ed8-a340-74e8d7ba66bc', '6d0119d3-3549-44b6-a953-388d881cc817', '4', '第二部分：基础入门', '{\"title\": \"Hello, World! —— 第一个C程序\", \"points\": [\"#include <stdio.h>\", \"int main() { printf(\\\"Hello, World!\\\\n\\\"); return 0; }\", \"解释：预处理指令、主函数、标准输出、返回值\", \"编译运行三步：gcc hello.c -o hello → ./hello\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 05:50:02.507466', '2026-02-02 05:52:47.065646', 'title_content', '{\"title\": \"Hello, World! —— 第一个C程序\", \"content\": [\"这是每个C程序员的起点：简洁、规范、可运行。\", \"核心代码：#include <stdio.h> —— 引入标准输入输出库。\", \"int main() { ... } —— 程序唯一入口，操作系统由此调用。\", \"printf(\\\"Hello, World!\\\\n\\\"); —— 向控制台输出字符串并换行。\", \"return 0; —— 表示程序成功结束，返回值供系统或父进程检查。\"], \"highlight\": \"#include <stdio.h>\\nint main() { printf(\\\"Hello, World!\\\\n\\\"); return 0; }\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('3eeeca71-5187-47a0-9a0a-f2874241caf1', '6d0119d3-3549-44b6-a953-388d881cc817', '5', '第二部分：基础入门', '{\"title\": \"C程序基本结构\", \"points\": [\"预处理指令（#include、#define）\", \"全局声明区（全局变量、函数声明）\", \"main()函数（程序唯一入口）\", \"语句块（{}包裹，以分号结尾）\", \"注释：// 单行 与 /* 多行 */\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 05:50:02.507719', '2026-02-02 05:52:48.727007', 'title_bullets', '{\"title\": \"C程序基本结构\", \"bullets\": [{\"icon\": \"fa-code\", \"text\": \"预处理指令区\", \"description\": \"以#开头，如#include引入头文件、#define定义宏，由预处理器在编译前处理。\"}, {\"icon\": \"fa-file-alt\", \"text\": \"全局声明区\", \"description\": \"位于函数外，可声明全局变量、函数原型（如int add(int, int);），作用域覆盖整个文件。\"}, {\"icon\": \"fa-play-circle\", \"text\": \"main()函数入口\", \"description\": \"每个C程序有且仅有一个main函数，是程序执行的起点，返回int类型表示运行状态。\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('d6658612-9429-462b-b172-b5a03ad7a440', '6d0119d3-3549-44b6-a953-388d881cc817', '6', '第二部分：基础入门', '{\"title\": \"数据类型与变量\", \"points\": [\"基本类型：int、float、double、char\", \"修饰符：short、long、signed、unsigned\", \"变量定义：类型名 变量名 = 初值;\", \"命名规则：字母/下划线开头，区分大小写，不可用关键字\", \"sizeof()查看类型字节数\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 05:50:02.507964', '2026-02-02 05:52:51.577803', 'title_bullets', '{\"title\": \"数据类型与变量\", \"bullets\": [{\"icon\": \"fa-font\", \"text\": \"基本数据类型\", \"description\": \"int（整型）、float（单精度浮点）、double（双精度浮点）、char（字符型），决定变量存储形式与取值范围。\"}, {\"icon\": \"fa-sliders-h\", \"text\": \"类型修饰符\", \"description\": \"short/long 调整长度；signed/unsigned 控制符号位，如 unsigned int 可表示更大正数范围。\"}, {\"icon\": \"fa-code\", \"text\": \"变量定义语法\", \"description\": \"遵循「类型名 变量名 = 初值;」格式，如 int count = 0; char flag = \'Y\'; 未初始化值为随机。\"}, {\"icon\": \"fa-ruler-combined\", \"text\": \"内存占用与范围\", \"description\": \"不同平台有差异：通常 int 为4字节（-2147483648~2147483647），char 为1字节（-128~127 或 0~255）。\"}, {\"icon\": \"fa-exclamation-triangle\", \"text\": \"命名规范建议\", \"description\": \"使用有意义的英文标识符（如 studentAge），避免关键字，区分大小写，推荐小驼峰命名法。\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('76917829-45e3-4196-9535-9ae5bd99b6c2', '6d0119d3-3549-44b6-a953-388d881cc817', '7', '第三部分：核心语法', '{\"title\": \"运算符与表达式\", \"points\": [\"算术：+ - * / % ++ --\", \"关系：== != > < >= <=\", \"逻辑：&& || !\", \"赋值：= += -= *= /= %=\", \"条件运算符：exp ? a : b\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 05:50:02.508202', '2026-02-02 05:52:53.847907', 'title_bullets', '{\"title\": \"运算符与表达式\", \"bullets\": [{\"icon\": \"fa-calculator\", \"text\": \"算术运算符\", \"description\": \"+ - * / % 用于数值计算；++ -- 实现自增/自减，注意前置与后置区别\"}, {\"icon\": \"fa-exchange-alt\", \"text\": \"关系运算符\", \"description\": \"== != > < >= <= 用于比较，结果为1（真）或0（假），常用于条件判断\"}, {\"icon\": \"fa-toggle-on\", \"text\": \"逻辑运算符\", \"description\": \"&&（与）、||（或）、!（非）组合布尔表达式，支持短路求值机制\"}, {\"icon\": \"fa-brain\", \"text\": \"运算符优先级\", \"description\": \"括号 > 算术 > 关系 > 逻辑 > 赋值；混合表达式须结合优先级与结合性理解\"}, {\"icon\": \"fa-code\", \"text\": \"表达式概念\", \"description\": \"由运算符和操作数组成的可求值式子，如 a + b > 5 || c == 0，有明确类型与值\"}, {\"icon\": \"fa-exclamation-triangle\", \"text\": \"常见陷阱提醒\", \"description\": \"避免混淆=（赋值）与==（相等）；%仅适用于整型；除零导致未定义行为\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('214d19f6-7deb-4cec-b432-e12ad2c1f191', '6d0119d3-3549-44b6-a953-388d881cc817', '8', '第三部分：核心语法', '{\"title\": \"输入与输出\", \"points\": [\"printf()：格式化输出（%d %f %c %s）\", \"scanf()：格式化输入（注意&取地址符）\", \"字符I/O：getchar()/putchar()\", \"常见陷阱：缓冲区残留、格式匹配错误\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 05:50:02.508735', '2026-02-02 05:52:53.969079', 'title_bullets', '{\"title\": \"输入与输出\", \"bullets\": [{\"icon\": \"fa-print\", \"text\": \"printf()：格式化输出\", \"description\": \"支持%d（整数）、%f（浮点）、%c（字符）、%s（字符串）等转换说明符，需包含<stdio.h>\"}, {\"icon\": \"fa-keyboard\", \"text\": \"scanf()：格式化输入\", \"description\": \"读取用户输入时，变量前必须加&取地址符（如&num），否则导致未定义行为\"}, {\"icon\": \"fa-font\", \"text\": \"字符级I/O函数\", \"description\": \"getchar()读单字符（返回int），putchar()写单字符；无需格式符，效率高、适合简单交互\"}, {\"icon\": \"fa-exclamation-triangle\", \"text\": \"常见陷阱提醒\", \"description\": \"scanf()后残留换行符可能影响后续输入；建议用getchar()清理缓冲区或使用fgets()替代\"}, {\"icon\": \"fa-code\", \"text\": \"典型使用示例\", \"description\": \"int x; scanf(\\\"%d\\\", &x); printf(\\\"值为：%d\\\\n\\\", x); char c = getchar(); putchar(c);\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('134248e1-b6c8-408b-b1d1-b606101958a7', '6d0119d3-3549-44b6-a953-388d881cc817', '9', '第三部分：核心语法', '{\"title\": \"流程控制语句\", \"points\": [\"if-else分支选择\", \"switch-case多路分支（需break防穿透）\", \"while循环（先判断后执行）\", \"do-while循环（先执行后判断）\", \"for循环（初始化；条件；迭代）\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 05:50:02.509133', '2026-02-02 05:52:50.470551', 'title_bullets', '{\"title\": \"流程控制语句\", \"bullets\": [{\"icon\": \"fa-code-branch\", \"text\": \"if-else分支选择\", \"description\": \"根据布尔表达式真假执行不同代码块，支持嵌套与else-if链\"}, {\"icon\": \"fa-sitemap\", \"text\": \"switch-case多路分支\", \"description\": \"适用于整型/字符型常量匹配；每个case后需break防止穿透执行\"}, {\"icon\": \"fa-sync-alt\", \"text\": \"while循环（先判断后执行）\", \"description\": \"条件为真时重复执行循环体；首次不满足则一次都不执行\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('35a5ab8f-9895-41c4-a1ff-f5b0f50f0630', '6d0119d3-3549-44b6-a953-388d881cc817', '10', '第三部分：核心语法', '{\"title\": \"数组与字符串\", \"points\": [\"一维数组：int arr[5] = {1,2,3};\", \"数组名即首地址，下标从0开始\", \"字符串本质是char数组，以\'\\\\0\'结尾\", \"常用函数：strlen()、strcpy()、strcat()、strcmp()\", \"字符数组 vs 字符指针区别\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 05:50:02.509331', '2026-02-02 05:52:40.173981', 'title_bullets', '{\"title\": \"数组与字符串\", \"bullets\": [{\"icon\": \"fa-table\", \"text\": \"一维数组定义与初始化\", \"description\": \"int arr[5] = {1,2,3}; 未显式赋值元素自动初始化为0\"}, {\"icon\": \"fa-hashtag\", \"text\": \"数组下标从0开始\", \"description\": \"arr[0]是首元素，arr[4]是末元素；越界访问无编译错误但行为未定义\"}, {\"icon\": \"fa-link\", \"text\": \"数组名即首地址\", \"description\": \"arr等价于&arr[0]，类型为int*；sizeof(arr)返回整个数组字节数\"}, {\"icon\": \"fa-font\", \"text\": \"字符串本质是char数组\", \"description\": \"如char s[] = \\\"abc\\\"; 实际存储为{\'a\',\'b\',\'c\',\'\\\\0\'}，共4字节\"}, {\"icon\": \"fa-terminal\", \"text\": \"以\'\\\\0\'作为字符串结束标志\", \"description\": \"printf(\\\"%s\\\", s)依赖\'\\\\0\'判断结尾；手动操作字符串时务必保留该终止符\"}, {\"icon\": \"fa-exclamation-triangle\", \"text\": \"常见陷阱提醒\", \"description\": \"字符数组未预留\'\\\\0\'空间、用==比较字符串（应使用strcmp）、gets()已废弃\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c8966975-381a-4357-ab4a-b101e35cff30', '6d0119d3-3549-44b6-a953-388d881cc817', '11', '第三部分：核心语法', '{\"title\": \"函数定义与调用\", \"points\": [\"函数三要素：返回类型、函数名、参数列表\", \"函数声明（原型）与定义分离\", \"形参传值 vs 地址传递（指针）\", \"局部变量与全局变量作用域\", \"递归函数示例：求阶乘\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 05:50:02.509535', '2026-02-02 05:52:40.472201', 'title_bullets', '{\"title\": \"函数定义与调用\", \"bullets\": [{\"icon\": \"fa-code\", \"text\": \"函数三要素：返回类型、函数名、参数列表\", \"description\": \"例如 int add(int a, int b) 中，int 是返回类型，add 是函数名，(int a, int b) 是参数列表\"}, {\"icon\": \"fa-file-alt\", \"text\": \"函数声明（原型）与定义分离\", \"description\": \"声明在头文件或主函数前（如 int max(int, int);），定义在后（含函数体），实现模块化与代码复用\"}, {\"icon\": \"fa-exchange-alt\", \"text\": \"形参传值：实参副本，修改不影响原变量\", \"description\": \"C语言默认按值传递，函数内对形参的修改仅作用于栈上副本，调用结束后即销毁\"}, {\"icon\": \"fa-link\", \"text\": \"地址传递：通过指针实现双向通信\", \"description\": \"将实参地址传入（如 swap(&x, &y)），函数内解引用 *p 修改原始内存，支持多值返回与大对象高效传递\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ece506de-60c5-4305-a7bf-0e3b509c26e3', '6d0119d3-3549-44b6-a953-388d881cc817', '12', '第四部分：进阶概念', '{\"title\": \"指针基础\", \"points\": [\"指针是存储地址的变量：int *p;\", \"取地址符 & 和解引用符 *\", \"指针与数组关系：arr ≡ &arr[0]\", \"指针运算：p++, p+i, *(p+i)\", \"空指针NULL与野指针防范\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 05:50:02.509754', '2026-02-02 05:52:40.523733', 'title_bullets', '{\"title\": \"指针基础\", \"bullets\": [{\"icon\": \"fa-arrow-right\", \"text\": \"指针是存储地址的变量\", \"description\": \"声明形式：int *p; 其中 * 表示 p 是指向 int 类型的指针变量\"}, {\"icon\": \"fa-hashtag\", \"text\": \"取地址符 & 获取变量地址\", \"description\": \"&a 返回变量 a 在内存中的起始地址，类型为 int*（假设 a 为 int）\"}, {\"icon\": \"fa-unlink\", \"text\": \"解引用符 * 访问所指内容\", \"description\": \"*p 表示读取或修改 p 所存储地址处的值，需确保 p 已初始化且有效\"}, {\"icon\": \"fa-th-list\", \"text\": \"数组名等价于首元素地址\", \"description\": \"arr ≡ &arr[0]，两者类型均为 int*（一维 int 数组），均可作指针使用\"}, {\"icon\": \"fa-exchange-alt\", \"text\": \"指针与数组可相互替代\", \"description\": \"p = arr; 等价于 p = &arr[0]; 后续可用 p[i] 或 *(p+i) 访问数组元素\"}, {\"icon\": \"fa-exclamation-triangle\", \"text\": \"关键安全提醒\", \"description\": \"使用指针前必须初始化（如 p = &a 或 p = malloc(...)），避免野指针和空指针解引用\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('400d7fb7-283c-4fd9-b312-215496ce066e', '6d0119d3-3549-44b6-a953-388d881cc817', '13', '第四部分：进阶概念', '{\"title\": \"结构体入门\", \"points\": [\"自定义复合类型：struct Student { char name[20]; int age; };\", \"定义变量：struct Student s1;\", \"成员访问：s1.age 或 (*ps).age 或 ps->age\", \"结构体数组与指针\", \"typedef简化结构体使用\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 05:50:02.509959', '2026-02-02 05:52:38.703009', 'title_bullets', '{\"title\": \"结构体入门\", \"bullets\": [{\"icon\": \"fa-cube\", \"text\": \"自定义复合类型\", \"description\": \"struct Student { char name[20]; int age; }; —— 将不同数据类型封装为一个逻辑整体\"}, {\"icon\": \"fa-user\", \"text\": \"结构体变量定义\", \"description\": \"struct Student s1; 或 struct Student s1 = {\\\"张三\\\", 20}; —— 声明并可选初始化实例\"}, {\"icon\": \"fa-arrow-right\", \"text\": \"点运算符访问成员\", \"description\": \"s1.age、s1.name —— 直接通过变量名访问其内部成员，最常用且直观\"}, {\"icon\": \"fa-code\", \"text\": \"指针解引用访问\", \"description\": \"(*ps).age —— 当ps为struct Student*类型时，先解引用再用点号访问\"}, {\"icon\": \"fa-long-arrow-alt-right\", \"text\": \"箭头运算符快捷访问\", \"description\": \"ps->age —— 等价于(*ps).age，专用于结构体指针，更简洁安全\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('bbe722ad-8df6-49e0-9f8d-75e3720e62f0', '6d0119d3-3549-44b6-a953-388d881cc817', '14', '第四部分：进阶概念', '{\"title\": \"文件操作简介\", \"points\": [\"FILE *fp; —— 文件指针类型\", \"打开：fopen(\\\"file.txt\\\", \\\"r/w/a\\\")\", \"读写：fscanf()/fprintf(), fgets()/fputs(), fread()/fwrite()\", \"关闭：fclose(fp)\", \"错误检查：fp == NULL判断\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 05:50:02.510248', '2026-02-02 05:52:42.076099', 'title_bullets', '{\"title\": \"文件操作简介\", \"bullets\": [{\"icon\": \"fa-file-alt\", \"text\": \"文件指针类型声明\", \"description\": \"FILE *fp; —— FILE是标准库定义的结构体类型，fp用于指向被打开的文件\"}, {\"icon\": \"fa-folder-open\", \"text\": \"文件打开与模式\", \"description\": \"fopen(\\\"file.txt\\\", \\\"r\\\")以只读方式打开；\\\"w\\\"覆盖写入；\\\"a\\\"追加写入；失败返回NULL\"}, {\"icon\": \"fa-download\", \"text\": \"格式化读取/写入\", \"description\": \"fscanf(fp, \\\"%d%s\\\", &n, str)从文件读取；fprintf(fp, \\\"%s: %d\\\\n\\\", name, score)向文件写入\"}, {\"icon\": \"fa-align-left\", \"text\": \"行级字符串读写\", \"description\": \"fgets(buf, size, fp)安全读一行（含换行符）；fputs(str, fp)写字符串不自动加换行\"}, {\"icon\": \"fa-hdd\", \"text\": \"二进制块读写\", \"description\": \"fread(ptr, size, count, fp)和fwrite(ptr, size, count, fp)高效处理结构体等二进制数据\"}, {\"icon\": \"fa-times-circle\", \"text\": \"资源管理规范\", \"description\": \"操作完成后必须调用fclose(fp)释放文件句柄；多次打开需确保一一对应关闭，避免资源泄漏\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('fc570d37-d149-40c1-a8c6-bcbccf0206cc', '6d0119d3-3549-44b6-a953-388d881cc817', '15', '第五部分：实训环节', '{\"title\": \"实训1：学生成绩管理系统（基础版）\", \"points\": [\"功能：录入3名学生姓名、学号、三科成绩\", \"计算每人的总分与平均分\", \"按平均分降序排序并输出\", \"技术点：结构体、数组、函数封装、排序算法（冒泡）\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 05:50:02.510522', '2026-02-02 05:52:38.696010', 'title_bullets', '{\"title\": \"实训1：学生成绩管理系统（基础版）\", \"bullets\": [{\"icon\": \"fa-user-graduate\", \"text\": \"功能目标\", \"description\": \"录入3名学生姓名、学号及语文、数学、英语三科成绩\"}, {\"icon\": \"fa-calculator\", \"text\": \"成绩计算\", \"description\": \"为每位学生自动计算总分与算术平均分（保留1位小数）\"}, {\"icon\": \"fa-sort-amount-down\", \"text\": \"排序输出\", \"description\": \"按平均分从高到低降序排列，输出完整成绩单\"}, {\"icon\": \"fa-code\", \"text\": \"核心知识点\", \"description\": \"综合运用结构体（封装学生信息）、数组（存储3名学生）、函数（模块化设计）\"}, {\"icon\": \"fa-bug\", \"text\": \"关键难点提示\", \"description\": \"注意输入缓冲区清理（如fflush(stdin)或getchar()），避免scanf残留换行符干扰\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('00b35670-e49b-49a2-aef9-02cf08dfac81', '6d0119d3-3549-44b6-a953-388d881cc817', '16', '第五部分：实训环节', '{\"title\": \"实训2：简易计算器\", \"points\": [\"支持 + - * / % 四则运算及括号（基础版）\", \"输入字符串表达式，解析并计算结果\", \"技术点：字符处理、switch分支、简单状态机\", \"扩展思考：如何支持浮点数与多位数？\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 05:50:02.510811', '2026-02-02 05:52:45.498368', 'title_bullets', '{\"title\": \"实训2：简易计算器\", \"bullets\": [{\"icon\": \"fa-calculator\", \"text\": \"功能目标\", \"description\": \"支持+ - * / %四则运算及圆括号，实现字符串表达式求值\"}, {\"icon\": \"fa-keyboard\", \"text\": \"输入输出方式\", \"description\": \"用户输入如\\\"3*(4+2)-8%3\\\"字符串，程序解析并输出数值结果\"}, {\"icon\": \"fa-code\", \"text\": \"核心算法思路\", \"description\": \"基于简单状态机：逐字符扫描，区分数字、运算符、括号，维护操作数栈与运算符栈\"}, {\"icon\": \"fa-brain\", \"text\": \"关键技术点\", \"description\": \"字符遍历与类型判断、switch处理多运算符分支、整型/浮点数转换、括号递归或栈匹配\"}, {\"icon\": \"fa-bug\", \"text\": \"典型难点提示\", \"description\": \"负数识别（如\\\"-5\\\"）、连续运算符处理（如\\\"3+-2\\\"）、除零检查、字符串转整数健壮性\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c5bbe015-96ff-49a9-8025-71fc950b5856', '6d0119d3-3549-44b6-a953-388d881cc817', '17', '第五部分：实训环节', '{\"title\": \"常见错误与调试技巧\", \"points\": [\"编译错误：缺少分号、括号不匹配、未声明函数\", \"运行时错误：数组越界、空指针解引用、栈溢出\", \"调试方法：printf调试法、GDB基础命令（run/break/print/next）\", \"使用-Wall开启全部警告\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 05:50:02.511117', '2026-02-02 05:52:47.298069', 'title_bullets', '{\"title\": \"常见错误与调试技巧\", \"bullets\": [{\"icon\": \"fa-exclamation-triangle\", \"text\": \"编译错误：分号缺失、括号不匹配、函数未声明\", \"description\": \"编译器报错行号明确，需逐行检查语法规范，尤其注意花括号配对和函数调用前的声明。\"}, {\"icon\": \"fa-bug\", \"text\": \"运行时错误：数组越界、空指针解引用、栈溢出\", \"description\": \"程序能编译但异常崩溃；越界访问内存、解引用NULL指针、递归过深或大数组局部定义易致栈溢出。\"}, {\"icon\": \"fa-terminal\", \"text\": \"printf调试法：插桩输出关键变量值与执行路径\", \"description\": \"在可疑代码段前后添加printf打印变量/状态，快速定位逻辑偏差，适用于简单场景和嵌入式环境。\"}, {\"icon\": \"fa-globe-americas\", \"text\": \"GDB基础命令：run启动、break设断点、print查变量\", \"description\": \"使用gdb ./a.out加载程序；break main设置入口断点；print i查看变量；next单步执行（不进函数）。\"}, {\"icon\": \"fa-step-forward\", \"text\": \"GDB进阶技巧：continue继续、bt看调用栈、info registers\", \"description\": \"continue恢复执行至下一断点；bt显示崩溃时函数调用链；info registers辅助分析寄存器状态。\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('63a149cb-548a-4ecb-98e8-926c1c74b911', '6d0119d3-3549-44b6-a953-388d881cc817', '18', '第六部分：总结与展望', '{\"title\": \"本课程重点回顾\", \"points\": [\"C语言语法骨架：变量→运算→控制流→函数→指针→结构体\", \"编程思维培养：分解问题、模块化设计、边界检查\", \"工程习惯：规范命名、清晰注释、错误处理\", \"调试能力比代码量更重要\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 05:50:02.511360', '2026-02-02 05:52:44.147200', 'title_bullets', '{\"title\": \"本课程重点回顾\", \"bullets\": [{\"icon\": \"fa-skeleton\", \"text\": \"C语言语法骨架\", \"description\": \"变量→运算→控制流→函数→指针→结构体，层层递进构建编程能力基石\"}, {\"icon\": \"fa-brain\", \"text\": \"编程思维培养\", \"description\": \"掌握问题分解、模块化设计与边界检查，提升逻辑严谨性与鲁棒性\"}, {\"icon\": \"fa-tools\", \"text\": \"工程习惯养成\", \"description\": \"坚持规范命名、清晰注释、健壮错误处理，为真实项目开发奠基\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('acdfe521-7894-4b0f-9e61-c516c0029561', '6d0119d3-3549-44b6-a953-388d881cc817', '19', '第六部分：总结与展望', '{\"title\": \"下一步学习建议\", \"points\": [\"深入：《C Primer Plus》《C和指针》\", \"实践：LeetCode简单题、开源小项目（如简易shell）\", \"拓展：学习数据结构（链表/栈/队列）与算法\", \"进阶方向：嵌入式开发、操作系统原理、逆向分析\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 05:50:02.511675', '2026-02-02 05:52:43.964710', 'title_bullets', '{\"title\": \"下一步学习建议\", \"bullets\": [{\"icon\": \"fa-book\", \"text\": \"深入系统学习\", \"description\": \"精读《C Primer Plus》夯实基础，辅以《C和指针》攻克核心难点，建立扎实的底层认知体系。\"}, {\"icon\": \"fa-code\", \"text\": \"坚持动手实践\", \"description\": \"每日1道LeetCode简单题巩固语法；参与开源小项目（如简易shell），提升工程能力与调试经验。\"}, {\"icon\": \"fa-sitemap\", \"text\": \"拓展数据结构\", \"description\": \"系统学习链表、栈、队列等线性结构，理解内存布局与操作逻辑，为算法进阶打下坚实基础。\"}]}');
