INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5dc613ca-1e16-4424-bd89-e43168542f9b', '0da568a3-0754-4b90-9d37-17429a5c996b', '0', NULL, '{\"title\": \"C语言教学入门\", \"points\": []}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 06:03:21.318243', '2026-02-02 06:03:29.168419', 'cover', '{\"title\": \"C语言教学入门\", \"subtitle\": \"夯实编程基础，迈向系统开发\", \"author\": \"计算机基础教研组\", \"department\": \"信息技术学院\", \"date\": \"2024年\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('acb9d9d5-b152-4993-9b65-70df370db630', '0da568a3-0754-4b90-9d37-17429a5c996b', '1', NULL, '{\"title\": \"课程目录\", \"points\": [\"C语言概述与开发环境\", \"基础语法与数据类型\", \"控制结构与函数\", \"数组、指针与字符串\", \"文件操作与综合实训\", \"总结与答疑\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 06:03:21.320011', '2026-02-02 06:03:29.959328', 'toc', '{\"title\": \"课程目录\", \"items\": [{\"index\": 1, \"text\": \"C语言概述与开发环境\"}, {\"index\": 2, \"text\": \"基础语法与数据类型\"}, {\"index\": 3, \"text\": \"控制结构与函数\"}, {\"index\": 4, \"text\": \"数组、指针与字符串\"}, {\"index\": 5, \"text\": \"文件操作与综合实训\"}, {\"index\": 6, \"text\": \"常见错误与调试技巧\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('08230dc1-4711-4f9b-ba71-ed00efaa12f8', '0da568a3-0754-4b90-9d37-17429a5c996b', '2', '第一部分：C语言基础', '{\"title\": \"C语言概述与开发环境\", \"points\": [\"C语言的历史与特点\", \"主流编译器介绍（GCC、Dev-C++、VS Code+MinGW）\", \"第一个程序：Hello World详解\", \"实训1：环境搭建与程序编译运行\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 06:03:21.320422', '2026-02-02 06:03:34.976614', 'title_bullets', '{\"title\": \"C语言概述与开发环境\", \"bullets\": [{\"icon\": \"fa-history\", \"text\": \"C语言的历史与特点\", \"description\": \"1972年诞生于贝尔实验室，兼具高级语言表达力与低级语言操控性；强调简洁、高效、可移植、贴近硬件。\"}, {\"icon\": \"fa-cogs\", \"text\": \"GCC编译器\", \"description\": \"开源标准编译器（GNU Compiler Collection），支持多平台，命令行驱动，Linux/macOS主流选择。\"}, {\"icon\": \"fa-desktop\", \"text\": \"Dev-C++集成环境\", \"description\": \"轻量级Windows IDE，内置MinGW-GCC，适合初学者快速编译调试，界面简洁、启动迅速。\"}, {\"icon\": \"fa-code\", \"text\": \"VS Code + MinGW组合\", \"description\": \"现代高效开发方案：VS Code提供智能编辑与调试，MinGW提供本地编译能力，跨平台可扩展性强。\"}, {\"icon\": \"fa-file-code\", \"text\": \"Hello World程序结构\", \"description\": \"包含预处理指令（#include）、主函数（main）、标准输出（printf）和返回值（return 0），体现C程序基本骨架。\"}, {\"icon\": \"fa-terminal\", \"text\": \"编译执行流程详解\", \"description\": \"源码→预处理→编译→汇编→链接→可执行文件；以gcc hello.c -o hello为例，分步理解构建全过程。\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('0f9d3459-4dba-4ee5-a451-27c4fc00cd9e', '0da568a3-0754-4b90-9d37-17429a5c996b', '3', '第一部分：C语言基础', '{\"title\": \"基础语法与数据类型\", \"points\": [\"标识符、关键字与注释规范\", \"整型、浮点型、字符型与布尔型\", \"常量与变量声明及初始化\", \"运算符与表达式（算术、关系、逻辑、位运算）\", \"实训2：简单计算器实现\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 06:03:21.320776', '2026-02-02 06:03:36.506472', 'title_bullets', '{\"title\": \"基础语法与数据类型\", \"bullets\": [{\"icon\": \"fa-font\", \"text\": \"标识符、关键字与注释规范\", \"description\": \"标识符需以字母或下划线开头；32个C关键字不可用作变量名；支持//单行与/* */多行注释。\"}, {\"icon\": \"fa-hashtag\", \"text\": \"整型、浮点型、字符型与布尔型\", \"description\": \"int/long（整型）、float/double（浮点型）、char（1字节字符）、_Bool或bool（C99起支持，值为0或1）。\"}, {\"icon\": \"fa-circle-dot\", \"text\": \"常量声明方式多样\", \"description\": \"字面常量（如123、3.14）、符号常量（#define PI 3.14）、枚举常量（enum {RED, GREEN}）均不可修改。\"}, {\"icon\": \"fa-variable\", \"text\": \"变量声明与初始化\", \"description\": \"格式：类型名 变量名 [= 初始值]；未初始化的局部变量值不确定，全局/静态变量默认初始化为0。\"}, {\"icon\": \"fa-code\", \"text\": \"类型修饰符灵活组合\", \"description\": \"可搭配signed/unsigned、short/long修饰整型；如unsigned long int、long double提升精度与范围。\"}, {\"icon\": \"fa-info-circle\", \"text\": \"数据类型大小与范围依赖平台\", \"description\": \"使用sizeof()和<limits.h>、<float.h>头文件获取具体实现细节，确保跨平台代码健壮性。\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('1f739a89-1699-48d1-9c2f-224a668c99d3', '0da568a3-0754-4b90-9d37-17429a5c996b', '4', '第二部分：程序控制与模块化', '{\"title\": \"控制结构与函数\", \"points\": [\"if-else、switch多分支选择\", \"while、do-while、for循环\", \"break、continue与goto（慎用）\", \"函数定义、声明、调用与参数传递\", \"实训3：成绩等级判定与阶乘计算\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 06:03:21.321063', '2026-02-02 06:03:32.443077', 'title_bullets', '{\"title\": \"控制结构与函数\", \"bullets\": [{\"icon\": \"fa-code\", \"text\": \"if-else与switch多分支选择\", \"description\": \"掌握条件判断逻辑：if-else实现二选一，switch优化等值多路分支，注意break防穿透\"}, {\"icon\": \"fa-sync-alt\", \"text\": \"while、do-while与for循环\", \"description\": \"while先判后执，do-while至少执行一次，for适合已知迭代次数的场景，三要素（初始化/条件/更新）缺一不可\"}, {\"icon\": \"fa-ban\", \"text\": \"break与continue控制流\", \"description\": \"break立即退出当前循环或switch；continue跳过本次循环剩余语句，直接进入下一次迭代\"}, {\"icon\": \"fa-exclamation-triangle\", \"text\": \"goto语句：慎用但需理解\", \"description\": \"可实现无条件跳转，易破坏结构化编程；仅限特定场景（如错误统一清理），须配注释说明用途\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('036801b3-8d78-48fa-bf53-504efeccaba1', '0da568a3-0754-4b90-9d37-17429a5c996b', '5', '第二部分：程序控制与模块化', '{\"title\": \"数组、指针与字符串\", \"points\": [\"一维/二维数组定义与遍历\", \"指针概念、取址与解引用\", \"指针与数组的关系\", \"字符串处理函数（strlen、strcpy、strcat等）\", \"实训4：学生成绩统计与字符串反转\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 06:03:21.321316', '2026-02-02 06:03:32.833045', 'title_bullets', '{\"title\": \"数组、指针与字符串\", \"bullets\": [{\"icon\": \"fa-table\", \"text\": \"一维/二维数组定义与遍历\", \"description\": \"掌握 int arr[5] 和 int mat[3][4] 声明方式；熟练使用 for 循环遍历，注意下标越界防护。\"}, {\"icon\": \"fa-mouse-pointer\", \"text\": \"指针概念、取址与解引用\", \"description\": \"指针是存储地址的变量；& 取地址，* 解引用；声明如 int *p = &a；强调类型匹配与初始化必要性。\"}, {\"icon\": \"fa-link\", \"text\": \"指针与数组的关系\", \"description\": \"数组名是首元素地址常量；arr[i] 等价于 *(arr + i)；指针可作数组名使用，支持算术运算与遍历。\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5785b6ad-14fd-4adb-a195-46d283bccd9a', '0da568a3-0754-4b90-9d37-17429a5c996b', '6', '第三部分：进阶应用与实训', '{\"title\": \"文件操作与综合实训\", \"points\": [\"文件打开/关闭（fopen/fclose）\", \"文本文件读写（fscanf/fprintf）\", \"二进制文件操作（fread/fwrite）\", \"实训5：学生信息管理系统（增删查存）\", \"实训6：简易通讯录项目实战\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 06:03:21.321614', '2026-02-02 06:03:34.269902', 'title_bullets', '{\"title\": \"文件操作与综合实训\", \"bullets\": [{\"icon\": \"fa-file-alt\", \"text\": \"文件打开/关闭（fopen/fclose）\", \"description\": \"掌握文件指针、打开模式（r/w/a/b）、错误检查及资源释放规范\"}, {\"icon\": \"fa-font\", \"text\": \"文本文件读写（fscanf/fprintf）\", \"description\": \"按格式化字符串读写，注意换行符处理、缓冲区安全与返回值校验\"}, {\"icon\": \"fa-database\", \"text\": \"二进制文件操作（fread/fwrite）\", \"description\": \"以字节块方式高效存取结构体等数据，规避编码与换行转换问题\"}, {\"icon\": \"fa-code\", \"text\": \"文件操作典型流程\", \"description\": \"fopen → 错误判断 → 读写操作 → fclose，严禁遗漏关闭导致资源泄漏\"}, {\"icon\": \"fa-laptop-code\", \"text\": \"综合实训任务示例\", \"description\": \"学生成绩管理：文本录入→二进制存储→查询统计→结果导出\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7a3b8b7e-3bec-44cc-a00f-df2877e23a50', '0da568a3-0754-4b90-9d37-17429a5c996b', '7', '第三部分：进阶应用与实训', '{\"title\": \"常见错误与调试技巧\", \"points\": [\"编译错误、链接错误与运行时错误辨析\", \"使用printf调试与断点调试入门\", \"内存泄漏与野指针预防\", \"代码风格与注释规范建议\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 06:03:21.322116', '2026-02-02 06:03:36.668230', 'title_bullets', '{\"title\": \"常见错误与调试技巧\", \"bullets\": [{\"icon\": \"fa-exclamation-triangle\", \"text\": \"三类错误精准辨析\", \"description\": \"编译错误（语法/头文件缺失）、链接错误（函数未定义/多重定义）、运行时错误（段错误/除零）\"}, {\"icon\": \"fa-bug\", \"text\": \"printf调试法实战\", \"description\": \"在关键路径插入带变量值的printf，配合fflush(stdout)确保即时输出，快速定位逻辑异常点\"}, {\"icon\": \"fa-crosshairs\", \"text\": \"断点调试入门\", \"description\": \"在IDE（如VS Code+GDB）中设置断点→单步执行→观察变量/调用栈，掌握Step Over/Into/Out核心操作\"}, {\"icon\": \"fa-shield-alt\", \"text\": \"内存泄漏预防策略\", \"description\": \"malloc/calloc后必配free；使用valgrind检测未释放内存；养成‘谁分配、谁释放’的编码习惯\"}, {\"icon\": \"fa-skull-crossbones\", \"text\": \"野指针根源与规避\", \"description\": \"避免使用未初始化/已释放指针；free后立即置NULL；启用编译器警告（-Wall -Wextra）捕获潜在风险\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('8c1d98cb-74c3-41ec-b2c5-14ca65b44146', '0da568a3-0754-4b90-9d37-17429a5c996b', '8', NULL, '{\"title\": \"课程总结\", \"points\": [\"C语言核心知识图谱回顾\", \"从语法到工程能力的成长路径\", \"后续学习建议（数据结构、嵌入式、算法）\", \"Q&A环节\"]}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 06:03:21.322387', '2026-02-02 06:03:38.474912', 'title_bullets', '{\"title\": \"课程总结\", \"bullets\": [{\"icon\": \"fa-sitemap\", \"text\": \"C语言核心知识图谱回顾\", \"description\": \"系统梳理语法基础、内存模型、指针机制与文件I/O等关键模块，构建结构化知识网络。\"}, {\"icon\": \"fa-road\", \"text\": \"从语法到工程能力的成长路径\", \"description\": \"以Hello World为起点，经实训项目锤炼，逐步掌握调试、模块化设计与代码健壮性保障能力。\"}, {\"icon\": \"fa-graduation-cap\", \"text\": \"后续学习建议：数据结构\", \"description\": \"深入链表、栈、队列、树等经典结构，夯实算法实现与内存管理双重基础。\"}, {\"icon\": \"fa-microchip\", \"text\": \"后续学习建议：嵌入式开发\", \"description\": \"结合STM32或Arduino平台，实践寄存器操作、中断处理与外设驱动开发。\"}, {\"icon\": \"fa-brain\", \"text\": \"后续学习建议：算法进阶\", \"description\": \"聚焦时间/空间复杂度分析，掌握排序、查找、递归及动态规划等核心算法思想。\"}]}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('46f3d407-08e2-4068-8455-5442b2a49fcb', '0da568a3-0754-4b90-9d37-17429a5c996b', '9', NULL, '{\"title\": \"谢谢聆听！\", \"points\": []}', NULL, NULL, 'HTML_MODEL_GENERATED', '2026-02-02 06:03:21.322619', '2026-02-02 06:03:33.849814', 'ending', '{\"title\": \"谢谢聆听！\", \"subtitle\": \"C语言教学入门课程圆满结束\", \"contact\": \"邮箱：teacher@cprogramming.edu.cn\"}');
COMMIT;

-- ----------------------------
-- Table structure for preset_styles
-- ----------------------------
DROP TABLE IF EXISTS `preset_styles`;
CREATE TABLE `preset_styles` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '风格名称',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '描述',
  `previewImage` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '描述图',
  `status` tinyint(1) DEFAULT NULL COMMENT '状态:0禁用1启用',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=17 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci ROW_FORMAT=DYNAMIC COMMENT='描述风格表';

-- ----------------------------
-- Records of preset_styles
-- ----------------------------
BEGIN;
INSERT INTO `preset_styles` (`id`, `name`, `description`, `previewImage`, `status`) VALUES (1, '简约商务', '`视觉描述：全局视觉语言应体现国际顶级咨询公司（如麦肯锡或波士顿咨询）的专业与稳重。整体风格追求极致的扁平化与秩序感，拒绝多余的装饰，强调信息的清晰传达。光照环境应为均匀的演播室漫射光，无明显的戏剧性阴影，确保画面干净透亮。\r\n  \r\n 配色与材质：背景色必须锁定为深沉、权威的“海军蓝”（Navy Blue, #0B1F3B），前景元素则使用纯白（ #FFFFFF）和微量的天蓝色（Sky Blue, #38BDF8）作为点缀；材质上避免复杂的纹理，采用哑光纸张质感或平滑的矢量色块。\r\n  \r\n  内容与排版：排版逻辑遵循严格的模块化网格系统。请生成清晰的几何分区，使用细线条或微弱的浅灰色色块（Light Gray, #E5E7EB）来划分内容区域。字体方面，应用粗壮有力的无衬线字体（如Helvetica或Roboto）作为标题，正文保持纤细清晰。图表元素应为扁平化的2D矢量图形，如简洁的柱状图或饼图，配色单一且克制。\r\n  \r\n  渲染要求：矢量插画风格，极高清晰度，无论是文字还是图形边缘都要锐利无锯齿，展现出严谨的商务美学，适合世界500强企业汇报场景。`', '/preset-previews/business-simple.webp', 1);
INSERT INTO `preset_styles` (`id`, `name`, `description`, `previewImage`, `status`) VALUES (2, '现代科技', '`视觉描述：全局视觉语言要融合赛博朋克与现代SaaS产品的未来感。整体氛围神秘、深邃且富有动感，仿佛置身于高科技的数据中心或虚拟空间。光照采用暗调环境下的自发光效果，模拟霓虹灯管和激光的辉光。\r\n  \r\n 配色与材质：背景色采用深邃的“午夜黑”（Midnight Black, #0B0F19），以衬托前景的亮度。主色调使用高饱和度的“电光蓝”（Electric Blue, #00A3FF）与“赛博紫”（Cyber Purple, #7C3AED）进行线性渐变，营造出流动的能量感。材质上大量运用半透明的玻璃、发光的网格线以及带有金属光泽的几何体。\r\n  \r\n  内容与排版：画面中应包含悬浮的3D几何元素（如立方体、四面体或芯片结构），这些元素应带有线框渲染（Wireframe）效果。排版布局倾向于不对称的动态平衡，使用具有科技感的等宽字体或现代无衬线体。背景中可以隐约添加电路板纹理、二进制代码流或点阵地图作为装饰，增加细节密度。\r\n  \r\n  渲染要求：Octane Render渲染风格，强调光线追踪、辉光（Bloom）效果和景深控制，呈现出精细的粒子特效和充满科技张力的视觉冲击力。`', '/preset-previews/tech-modern.webp', 1);
INSERT INTO `preset_styles` (`id`, `name`, `description`, `previewImage`, `status`) VALUES (3, '严谨学术', '`视觉描述：全局视觉语言应模仿高质量印刷出版物或经典论文的排版风格，传达理性、客观和知识的厚重感。整体氛围安静、克制，没有任何干扰视线的炫光或过度设计。画面必须铺满全屏，严禁出现书本装订线、纸张边缘、卷角、阴影或任何形式的边框。背景不应该呈现三维立体，而应该以二维平面方式呈现。\r\n  \r\n 配色与材质：背景色严格限制为“米白色”（Off-white, #F8F7F2），模拟高级道林纸的质感。前景色仅使用纯黑（#000000）、深炭灰（Charcoal, #1F2937）和作为强调色的深红（Deep Red, #7F1D1D）或深蓝（Deep Blue, #1E3A8A）（这种强调色占比不超过5%）。材质完全呈现为高质量的纸质印刷效果，具有细腻的纸张纹理。\r\n  \r\n  内容与排版：排版必须遵循经典的版式设计原则，拥有宽阔的页边距。请使用带有衬线的字体（类似Times New Roman或Garamond）来体现传统与正式。视觉元素主要由精细的黑色线条框（Black, #000000）、标准的学术表格样式和黑白线稿插图（Black, #000000 / White, #FFFFFF）组成。布局上采用左右分栏或上下结构的严谨对齐方式。\r\n  \r\n  渲染要求：超高分辨率扫描件风格，强调字体的灰度抗锯齿效果和线条的锐度，画面如同精装学术期刊的内页，展现出绝对的专业性与权威性。不应该存在任何形式的页面边框，比如黑色边框或者阴影边线。`', '/preset-previews/academic-formal.webp', 1);
INSERT INTO `preset_styles` (`id`, `name`, `description`, `previewImage`, `status`) VALUES (4, '活泼创意', '`视觉描述：全局视觉语言要像一个充满活力的初创公司Pitch Deck或儿童教育应用界面。整体氛围轻松、愉悦、充满想象力，打破常规的束缚。光照明亮且充满阳光感，色彩之间没有阴影，呈现彻底的扁平化。\r\n  \r\n 配色与材质：背景色使用高明度的“暖黄色”（Warm Yellow, #FFD54A）。配色方案极其大胆，混合使用鲜艳的“活力橙”（Vibrant Orange, #FF6A00）、“草绿”（Grass Green, #22C55E）和“天蓝”（Sky Blue, #38BDF8），形成孟菲斯（Memphis）风格的撞色效果。材质上模拟手绘涂鸦、剪纸或粗糙边缘的矢量插画。\r\n  \r\n  内容与排版：画面内容应包含手绘风格的插图元素，如涂鸦箭头、星星、波浪线和不规则的有机形状色块。排版上允许文字倾斜、重叠或跳跃，打破僵硬的网格。字体选用圆润可爱的圆体或手写体。请在角落放置一些拟人化的可爱物体或夸张的对话气泡。\r\n  \r\n  渲染要求：Dribbble热门插画风格，色彩鲜艳平涂，线条流畅且富有弹性，视觉上给人一种快乐、友好且极具亲和力的感觉。`', '/preset-previews/creative-fun.webp', 1);
INSERT INTO `preset_styles` (`id`, `name`, `description`, `previewImage`, `status`) VALUES (5, '极简清爽', '`视觉描述：全局视觉语言借鉴北欧设计（Scandinavian Design）和Kinfolk杂志的审美。整体氛围空灵、静谧，强调“少即是多”的哲学。光照采用极柔和的漫反射天光，阴影非常淡且边缘模糊，营造出空气感。\r\n  \r\n  配色与材质：背景色为极浅的“雾霾灰”（Haze Gray, #F5F5F7）。前景色仅使用中灰色（Mid Gray, #6B7280）和低饱和度的莫兰迪色系（如灰蓝（Morandi Gray Blue, #7A8FA6））作为微小的点缀。材质上体现细腻的哑光质感，偶尔出现一点点石膏（Plaster）的微纹理。\r\n  \r\n  内容与排版：构图的核心是“留白”（Negative Space），留白面积应占据画面的70%以上。排版极为克制，文字字号较小，行间距宽大，使用纤细优雅的非衬线字体。视觉锚点是简单的几何线条构成的图标，布局上追求绝对的平衡。\r\n  \r\n  渲染要求：极简主义摄影风格，高动态范围（HDR），画面极其干净，没有任何噪点，展现出一种画廊般的艺术陈列感。`', '/preset-previews/minimalist-clean.webp', 1);
INSERT INTO `preset_styles` (`id`, `name`, `description`, `previewImage`, `status`) VALUES (6, '高端奢华', '`视觉描述：全局视觉语言要融合高端腕表广告或五星级酒店的品牌形象。整体氛围神秘、高贵、独一无二。光照采用戏剧性的伦勃朗光或聚光灯效果，重点照亮关键元素，其余部分隐没在黑暗中。\r\n  \r\n  配色与材质：背景色严格锁定为深沉的“曜石黑”（Obsidian Black, #0B0B0F）。前景色主要由“香槟金”（Champagne Gold, #F7E7CE）构成。材质上必须体现昂贵的触感，核心组合为：背景呈现哑光黑天鹅绒质感，前景装饰呈现拉丝金属质感。\r\n  \r\n  内容与排版：排版采用经典的居中对齐或对称布局，强调仪式感。字体必须使用高雅的衬线体（Serif），字间距适当加宽以体现尊贵。画面中可以加入细致的金色边框线条、Art Deco风格的装饰纹样。如果有3D物体，应呈现出珠宝般的抛光质感。\r\n  \r\n  渲染要求：电影级写实渲染，强调材质的物理属性（PBR），特别是金属的高光反射和丝绒的漫反射细节，画面呈现出奢侈品广告大片的高级质感。`', '/preset-previews/luxury-premium.webp', 1);
INSERT INTO `preset_styles` (`id`, `name`, `description`, `previewImage`, `status`) VALUES (7, '自然清新', '`视觉描述：全局视觉语言旨在唤起人们对大自然、环保和健康生活的向往，类似全食超市（Whole Foods）或Aesop的品牌视觉。整体氛围治愈、透气、有机。光照模拟清晨穿过树叶的斑驳阳光（丁达尔效应），温暖而柔和。\r\n  \r\n  配色与材质：背景色采用柔和的“米色”（Beige, #EAD9C6）。配色方案取自自然界，重点使用森林绿（Forest Green, #14532D）和大地棕（Earth Brown, #7A4E2D）。材质上强调天然纹理，如再生纸的颗粒感和植物叶片的脉络。\r\n  \r\n  内容与排版：画面中应融合真实的自然元素，主要是伸展的绿植叶片，这些元素可以作为背景装饰或前景框架。排版使用圆润亲和的字体。布局上可以稍微松散，模仿自然生长的形态。阴影处理要柔和自然，避免生硬的黑色投影。\r\n  \r\n  渲染要求：微距摄影风格结合3D渲染，强调植物表面的透光感（Subsurface Scattering）和自然材质的细腻纹理，画面清新淡雅，令人心旷神怡。`', '/preset-previews/nature-fresh.webp', 1);
INSERT INTO `preset_styles` (`id`, `name`, `description`, `previewImage`, `status`) VALUES (8, '渐变活力', '`视觉描述：全局视觉语言对标现代科技独角兽公司（如Stripe或Linear）的官网视觉，呈现一种极光般的流动美感。整体氛围梦幻、通透且富有呼吸感，避免刺眼的撞色，强调色彩之间的优雅融合。\r\n\r\n  配色与材质：背景即前景，使用全屏的弥散渐变色。配色方案采用高雅且和谐的“全息色系”，以深邃的“宝石蓝”（Royal Blue, #2563EB）为基底，平滑过渡到“紫罗兰”（Violet, #7C3AED）和明亮的“洋红色”（Magenta, #DB2777）。颜色之间如水彩般晕染，没有生硬的边界。材质上锁定为“磨砂玻璃（Frosted Glass）”质感，让色彩看起来像是透过一层雾面屏透出来的，增加朦胧的高级感。插画使用有质感的半立体彩色设计。\r\n\r\n  内容与排版：画面核心是缓慢流动的有机波浪形状，形态柔和自然。排版上使用醒目的粗体无衬线字（Bold Sans-serif），文字颜色为纯白（#FFFFFF），以确保在多彩背景上的绝对清晰度。界面元素采用“玻璃拟态”（Glassmorphism），即高透明度的白色圆角卡片，带有细腻的白色描边和背景模糊效果。\r\n\r\n  渲染要求：C4D流体模拟渲染，强调“丝绸”般的顺滑光泽，配合轻微的噪点（Grain）增加质感，色彩饱满但不刺眼，展现出流光溢彩的现代数字美学。`', '/preset-previews/gradient-vibrant.webp', 1);
COMMIT;

-- ----------------------------
-- Table structure for projects
-- ----------------------------
DROP TABLE IF EXISTS `projects`;
CREATE TABLE `projects` (
  `id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `idea_prompt` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `outline_text` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `description_text` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `extra_requirements` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `creation_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `template_image_path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `status` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `template_style` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `export_extractor_method` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `export_inpaint_method` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `user_id` int DEFAULT NULL,
  `render_mode` varchar(20) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'image',
  `scheme_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci ROW_FORMAT=DYNAMIC;

